const p = msg.payload || {};
const now = Date.now();

const pumpTime = Math.max(0, Math.round(Number(p.pumpTime ?? 0)));
const maxPump = Math.max(1, Math.round(Number(p.maxPump ?? 60)));
const finalPumpTime = Math.min(pumpTime, maxPump);

if (finalPumpTime <= 0) {
  msg.payload = {
    ...p,
    action: 'block',
    reason: 'invalid_pump_time',
    pumpTime: finalPumpTime,
    maxPump,
    now
  };
  return [null, msg];
}

msg.payload = {
  ...p,
  action: p.action || 'auto_water',
  reason: p.reason || '',
  pumpTime: finalPumpTime,
  maxPump,
  pumpStartedAt: now,
  lastIrr: now,
  last_irrigation_ms: now
};

return [msg, null];

const p = msg.payload;
const now = Date.now();

let rawLast = null;

if (typeof p === 'string') {
    rawLast = p;
} else if (p && typeof p === 'object') {
    rawLast = p.state ?? p.value ?? p.lastIrr ?? p.last_irrigation_ms ?? p.last_irrigation ?? null;
} else {
    rawLast = null;
}

const lastIrr = rawLast ? Date.parse(String(rawLast)) : NaN;
const minGap = 15;
const gapMs = minGap * 60000;

if (!Number.isFinite(lastIrr)) {
    msg.payload = {
        cooldownActive: false,
        cooldownAllowed: true,
        reason: 'no_last_irrigation_found',
        rawLast,
        now,
        minGap
    };
    return [msg, null];
}

const deltaMs = now - lastIrr;

if (deltaMs < gapMs) {
    msg.payload = {
        cooldownActive: true,
        cooldownAllowed: false,
        action: 'block',
        reason: 'cooldown_active',
        cooldownRemainingMin: Math.ceil((gapMs - deltaMs) / 60000),
        cooldownRemainingSec: Math.ceil((gapMs - deltaMs) / 1000),
        rawLast,
        lastIrr,
        now,
        minGap,
        cooldownCheck: { lastIrr, now, deltaMs, gapMs }
    };
    return [null, msg];
}

msg.payload = {
    coreDataObj: { ...p },
    cooldownActive: false,
    cooldownAllowed: true,
    rawLast,
    lastIrr,
    now,
    minGap,
    cooldownCheck: { lastIrr, now, deltaMs, gapMs }
};

return [msg, null];

