let p = msg.payload || {};

const phaseMode = String(p.phaseMode || p.phasemode || "").toLowerCase();
const intent = Number(p.intent ?? 0);

const phaseMap = {
    "gen_1": 1,
    "gen_2": 2,
    "gen_3": 3,
    "gen_4": 4,
    "gen_5": 5,
    "veg_6": 6,
    "veg_7": 7,
    "veg_8": 8,
    "veg_9": 9,
    "veg_10": 10,
    "flower_6": 6,
    "flower_7": 7,
    "flower_8": 8,
    "flower_9": 9,
    "flower_10": 10
};

let idx = phaseMap[phaseMode] ?? 1;

// Optionales Feintuning über intent
// Beispiel: intent 3 = neutral, kleiner = trockener/früher, größer = generativer/später
if (Number.isFinite(intent) && intent > 0) {
    if (intent <= 2) idx -= 1;
    else if (intent >= 8) idx += 1;
}

idx = Math.max(1, Math.min(10, idx));

msg.payload = p;
msg.payload.intentprofileindex = idx;
msg.payload.computedProfileIndex = idx;

return msg;

