        "func": "const p = msg.payload || {};

const dryRun = !!p.dryRun;
const action = String(p.action || 'block');
const reason = String(p.reasons || p.reason || '');
const maxPump = Number(p.maxPump || 60);
const pumpTime = Math.max(0, Math.min(Number(p.pumpTime || 0), maxPump));
const shotSize = Number.isFinite(Number(p.shotSize)) ? Number(p.shotSize) : 0;

msg.payload = {
  ...p,
  pumpTime,
  shotSize,
  dryRun,
  gateAction: action,
  gateReason: reason,
  gatePassed: action === 'auto_water' || action === 'fallback_water' || action === 'manual'
};

if (dryRun) {
  msg.payload.gatePassed = false;
  msg.payload.gateReason = reason ? `${reason},dry_run` : 'dry_run';
  return [msg, null];
}

if (action === 'auto_water' || action === 'fallback_water') {
  return [msg, null];
}

if (action === 'manual') {
  return [null, msg];
}

return [null, msg];",
